/* ─── Favorites / Recently Used persistence ─────────────────────────── */
const FAVORITES_KEY = 'aura_strategy_favorites';
const RECENT_KEY = 'aura_strategy_recent';

function getFavorites() {
  try { return JSON.parse(localStorage.getItem(FAVORITES_KEY) || '[]'); } catch { return []; }
}
function setFavoritesStorage(keys) {
  localStorage.setItem(FAVORITES_KEY, JSON.stringify(keys));
}
function getRecent() {
  try { return JSON.parse(localStorage.getItem(RECENT_KEY) || '[]'); } catch { return []; }
}
function pushRecent(key) {
  const recent = getRecent().filter(k => k !== key);
  recent.unshift(key);
  localStorage.setItem(RECENT_KEY, JSON.stringify(recent.slice(0, 10)));
}

