/* ─── Infer category from strategy name/label ────────────────────────── */
function inferCategory(strategy) {
  if (strategy.category) return strategy.category;
  const label = (strategy.label || strategy.name || '').toLowerCase();
  if (label.includes('breakout') || label.includes('break')) return 'breakout';
  if (label.includes('momentum') || label.includes('trend') || label.includes('power hour')) return 'momentum';
  if (label.includes('reversal') || label.includes('bounce') || label.includes('pullback') || label.includes('snap back') || label.includes('horseshoe')) return 'reversal';
  if (label.includes('mean') || label.includes('reversion') || label.includes('oscillat')) return 'mean-reversion';
  if (label.includes('volume') || label.includes('stagger')) return 'volume';
  if (label.includes('crypto') || label.includes('btc') || label.includes('eth')) return 'crypto';
  return strategy.category || '';
}

