/* ─── Signal tier classification ──────────────────────────────────────── */
/* Based on precision/win-rate thresholds from the tier-gating strategy:
   ULTRA (95%+ win rate) = Institutional, HIGH CONVICTION (80%+ win rate) = Pro,
   STANDARD (<80%) = Trader tier */
function classifySignalTier(strategy) {
  const wr = strategy.stats?.avg_win_rate;
  const sharpe = strategy.stats?.sharpe ?? strategy.stats?.avg_sharpe;
  if (wr == null) return null;
  if (wr >= 95 || (wr >= 90 && sharpe != null && sharpe >= 3.0)) return 'ultra';
  if (wr >= 80 || (wr >= 70 && sharpe != null && sharpe >= 2.0)) return 'high_conviction';
  return 'standard';
}

