/* Resolve a strategy's display status: live / paper / suppressed / active */
const resolveStatus = (strategy) => {
  if (strategy.promotion_status === 'live') return 'live';
  if (strategy.promotion_status === 'paper') return 'paper';
  if (strategy.status === 'suppressed' || strategy.promotion_status === 'suppressed') return 'suppressed';
  return 'active';
};

/* ─── Risk rating from max drawdown ─────────────────────────────────── */
function computeRiskRating(stats) {
  const dd = stats?.max_drawdown;
  if (dd == null) return null;
  const absDd = Math.abs(dd);
  if (absDd <= 0.05) return 1;
  if (absDd <= 0.10) return 2;
  if (absDd <= 0.20) return 3;
  if (absDd <= 0.35) return 4;
  return 5;
}

