/* Mini sparkline — generates a small equity-like curve from strategy stats */
const MiniSparkline = React.memo(function MiniSparkline({ winRate, avgReturn, trades, width = 80, height = 28 }) {
  if (!trades || trades < 3) return null;
  const wr = (winRate || 50) / 100;
  const ret = avgReturn || 0.02;
  const pts = Math.min(trades, 40);
  const curve = [100];
  for (let i = 1; i <= pts; i++) {
    const win = (i / pts) < wr;
    const r = win ? Math.abs(ret) * 0.8 : -Math.abs(ret) * 0.6;
    const jitter = Math.sin(i * 5.7 + (winRate || 0)) * 0.004;
    curve.push(curve[curve.length - 1] * (1 + r + jitter));
  }
  // Smooth into monotonic trend
  const sorted = [...curve].sort((a, b) => a - b);
  const final = curve.map((v, i) => {
    const progress = i / curve.length;
    return sorted[0] + (sorted[sorted.length - 1] - sorted[0]) * progress + (v - curve[0]) * 0.25;
  });
  const min = Math.min(...final);
  const max = Math.max(...final);
  const range = max - min || 1;
  const isUp = final[final.length - 1] >= final[0];
  const color = isUp ? colors.green : colors.red;
  const d = final.map((v, i) =>
    `${i === 0 ? 'M' : 'L'}${(i / (final.length - 1) * width).toFixed(1)},${(height - 2 - ((v - min) / range) * (height - 4)).toFixed(1)}`
  ).join(' ');
  return (
    <svg width={width} height={height} className={s.sparkline}>
      <path d={d} fill="none" stroke={color} strokeWidth="1.5" strokeLinejoin="round" />
    </svg>
  );
});

/* Color-coded metric cell like TI grid */
function MetricCell({ value, format, thresholds, center }) {
  let display = '\u2014';
  let color = colors.textSecondary;
  if (value != null) {
    display = format ? format(value) : value;
    if (thresholds) {
      for (const [threshold, c] of thresholds) {
        if (value >= threshold) { color = c; break; }
      }
    }
  }
  return (
    <td className={s.metricCell} style={{
      color, textAlign: center ? 'center' : 'left',
      background: value != null && thresholds ? `${color}08` : 'transparent',
    }}>
      {display}
    </td>
  );
}

/* Trade count indicator — visual bar showing vetting progress */
function TradeBar({ count }) {
  const pct = Math.min((count / MIN_TRADES_VETTED) * 100, 100);
  const vetted = count >= MIN_TRADES_VETTED;
  const color = vetted ? colors.green : count >= MIN_TRADES_VETTED / 2 ? colors.amber : colors.red;
  return (
    <div className={s.tradeBar}>
      <div className={s.tradeBarTrack}>
        <div className={s.tradeBarFill} style={{ width: `${pct}%`, background: color }} />
      </div>
      <span className={s.tradeBarCount} style={{ color }}>
        {count}
      </span>
      {!vetted && (
        <span className={s.tradeBarNeedsData}>
          needs data
        </span>
      )}
    </div>
  );
}

/* Quick Stats Bar */
function QuickStatsBar({ strategies }) {
  if (!strategies || strategies.length === 0) return null;

  const total = strategies.length;
  const liveCount = strategies.filter(s => resolveStatus(s) === 'live').length;
  const paperCount = strategies.filter(s => resolveStatus(s) === 'paper').length;
  const suppressedCount = strategies.filter(s => resolveStatus(s) === 'suppressed').length;

  const winRates = strategies
    .map(s => s.stats?.avg_win_rate)
    .filter(v => v != null && v > 0);
  const avgWinRate = winRates.length > 0
    ? (winRates.reduce((a, b) => a + b, 0) / winRates.length).toFixed(1)
    : null;

  const sharpeVals = strategies
    .map(s => s.stats?.sharpe ?? s.stats?.avg_sharpe)
    .filter(v => v != null && !isNaN(v));
  const avgSharpe = sharpeVals.length > 0
    ? (sharpeVals.reduce((a, b) => a + b, 0) / sharpeVals.length).toFixed(2)
    : null;

  const drawdowns = strategies
    .map(s => s.stats?.max_drawdown)
    .filter(v => v != null && !isNaN(v));
  const avgDrawdown = drawdowns.length > 0
    ? (drawdowns.reduce((a, b) => a + b, 0) / drawdowns.length * 100).toFixed(1)
    : null;

  const ultraCount = strategies.filter(s => classifySignalTier(s) === 'ultra').length;
  const highConvCount = strategies.filter(s => classifySignalTier(s) === 'high_conviction').length;

  const stats = [
    { label: 'Total', value: total, color: colors.textPrimary },
    { label: 'Live', value: liveCount, color: colors.green },
    { label: 'Paper', value: paperCount, color: colors.blue },
    { label: 'Suppressed', value: suppressedCount, color: colors.red },
    { label: 'Avg Win Rate', value: avgWinRate != null ? `${avgWinRate}%` : '--', color: avgWinRate >= 55 ? colors.green : avgWinRate >= 45 ? colors.amber : colors.textSecondary },
    { label: 'Avg Sharpe', value: avgSharpe != null ? avgSharpe : '--', color: avgSharpe >= 1.5 ? colors.green : avgSharpe >= 0.5 ? colors.amber : colors.textSecondary },
    { label: 'Avg Max DD', value: avgDrawdown != null ? `${avgDrawdown}%` : '--', color: avgDrawdown != null && Math.abs(avgDrawdown) <= 10 ? colors.green : Math.abs(avgDrawdown) <= 20 ? colors.amber : colors.red },
    { label: 'ULTRA', value: ultraCount, color: '#3FB950' },
    { label: 'High Conv.', value: highConvCount, color: '#F59E0B' },
  ];

  return (
    <div className={s.quickStatsBar}>
      {stats.map((stat, i) => (
        <div key={stat.label} className={s.quickStatCell}>
          {i > 0 && <div className={s.quickStatDivider} />}
          <div className={s.quickStatLabel}>{stat.label}</div>
          <div className={s.quickStatValue} style={{ color: stat.color }}>{stat.value}</div>
        </div>
      ))}
    </div>
  );
}

