/* ─── Recently Used Section ─────────────────────────────────────────── */
function RecentlyUsedSection({ strategies, favorites, onToggleFavorite, onNavigate }) {
  const recentKeys = getRecent();
  const recentStrategies = useMemo(() => {
    if (!strategies || recentKeys.length === 0) return [];
    return recentKeys
      .map(k => strategies.find(s => s.key === k))
      .filter(Boolean)
      .slice(0, 3);
  }, [strategies, recentKeys]);

  if (recentStrategies.length === 0) return null;

  return (
    <div className={s.recentSection}>
      <div className={s.recentHeader}>
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={colors.blue} strokeWidth="2">
          <circle cx="12" cy="12" r="10" />
          <polyline points="12 6 12 12 16 14" />
        </svg>
        <span className={s.recentTitle}>Recently Viewed</span>
      </div>
      <div className={s.recentCards}>
        {recentStrategies.map(strategy => {
          const stats = strategy.stats || {};
          const trades = stats.total_trades || 0;
          const riskRating = computeRiskRating(stats);
          const cat = inferCategory(strategy);
          return (
            <div
              key={strategy.key}
              className={s.recentCard}
              onClick={() => onNavigate(strategy)}
            >
              <div className={s.recentCardTop}>
                <CategoryIcon category={cat} size={14} />
                <span className={s.recentCardName}>{strategy.label}</span>
                <FavoriteStar
                  active={favorites.includes(strategy.key)}
                  onClick={(e) => { e.stopPropagation(); onToggleFavorite(strategy.key); }}
                />
              </div>
              <div className={s.recentCardSparkline}>
                <MiniSparkline winRate={stats.avg_win_rate} avgReturn={stats.avg_return} trades={trades} width={120} height={24} />
              </div>
              <div className={s.recentCardStats}>
                <WinRateBadge winRate={stats.avg_win_rate} />
                <RiskBar rating={riskRating} />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ─── Compare Side-by-Side Modal ────────────────────────────────────── */
function ComparePanel({ strategies, selectedKeys, onClose }) {
  const selected = useMemo(
    () => selectedKeys.map(k => strategies.find(s => s.key === k)).filter(Boolean),
    [strategies, selectedKeys]
  );
  if (selected.length < 2) return null;

  const metrics = [
    { label: 'Win Rate', key: 'avg_win_rate', fmt: v => v != null ? `${v}%` : '--', hi: 60, mid: 45 },
    { label: 'Sharpe', key: 'sharpe', alt: 'avg_sharpe', fmt: v => v != null ? v.toFixed(2) : '--', hi: 1.5, mid: 0.5 },
    { label: 'Avg Return', key: 'avg_return', fmt: v => v != null ? `${(v * 100).toFixed(1)}%` : '--', hi: 0.03, mid: 0 },
    { label: 'Total Return', key: 'total_return', fmt: v => v != null ? `${(v * 100).toFixed(1)}%` : '--', hi: 0.1, mid: 0 },
    { label: 'Profit Factor', key: 'profit_factor', alt: 'avg_pf', fmt: v => v != null ? v.toFixed(2) : '--', hi: 2.0, mid: 1.3 },
    { label: 'Max Drawdown', key: 'max_drawdown', fmt: v => v != null ? `${(v * 100).toFixed(1)}%` : '--', hi: -0.05, mid: -0.15 },
    { label: 'Trades', key: 'total_trades', fmt: v => v != null ? v.toLocaleString() : '--', hi: 20, mid: 10 },
    { label: 'Score', key: 'avg_score', fmt: v => v != null ? v.toFixed(1) : '--', hi: 20, mid: 10 },
    { label: 'Risk Rating', key: '_risk', fmt: v => v != null ? `${v}/5` : '--', hi: 1, mid: 3 },
  ];

  function getVal(strat, m) {
    if (m.key === '_risk') return computeRiskRating(strat.stats);
    return strat.stats?.[m.key] ?? (m.alt ? strat.stats?.[m.alt] : null) ?? null;
  }

  function metricColor(val, m) {
    if (val == null) return colors.textSecondary;
    if (m.key === '_risk') return val <= 2 ? colors.green : val <= 3 ? colors.amber : colors.red;
    if (val >= m.hi) return colors.green;
    if (val >= m.mid) return colors.amber;
    return colors.red;
  }

  // Find best value per metric
  function bestIdx(m) {
    const vals = selected.map(st => getVal(st, m));
    if (m.key === 'max_drawdown' || m.key === '_risk') {
      // Lower is better
      let best = Infinity, bi = -1;
      vals.forEach((v, i) => { if (v != null && Math.abs(v) < best) { best = Math.abs(v); bi = i; } });
      return bi;
    }
    let best = -Infinity, bi = -1;
    vals.forEach((v, i) => { if (v != null && v > best) { best = v; bi = i; } });
    return bi;
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: 40 }}
      className={s.comparePanel}
    >
      <div className={s.comparePanelHeader}>
        <span className={s.comparePanelTitle}>Strategy Comparison</span>
        <button onClick={onClose} className={s.comparePanelClose}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
        </button>
      </div>
      <div className={s.comparePanelScroll}>
        <table className={s.compareTable}>
          <thead>
            <tr>
              <th className={s.compareThLabel}>Metric</th>
              {selected.map(st => (
                <th key={st.key} className={s.compareThStrat}>
                  <CategoryIcon category={inferCategory(st)} size={12} />
                  <span>{st.label}</span>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {/* Sparkline row */}
            <tr className={s.compareTr}>
              <td className={s.compareTdLabel}>30d Curve</td>
              {selected.map(st => (
                <td key={st.key} className={s.compareTdVal}>
                  <MiniSparkline
                    winRate={st.stats?.avg_win_rate}
                    avgReturn={st.stats?.avg_return}
                    trades={st.stats?.total_trades || 0}
                    width={100}
                    height={26}
                  />
                </td>
              ))}
            </tr>
            {metrics.map(m => {
              const bi = bestIdx(m);
              return (
                <tr key={m.label} className={s.compareTr}>
                  <td className={s.compareTdLabel}>{m.label}</td>
                  {selected.map((st, i) => {
                    const val = getVal(st, m);
                    return (
                      <td
                        key={st.key}
                        className={s.compareTdVal}
                        style={{
                          color: metricColor(val, m),
                          fontWeight: i === bi ? 700 : 500,
                          background: i === bi ? 'rgba(63,185,80,0.06)' : 'transparent',
                        }}
                      >
                        {m.fmt(val)}
                        {i === bi && val != null && <span className={s.compareBestBadge}>BEST</span>}
                      </td>
                    );
                  })}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </motion.div>
  );
}

